import type { NextRequest } from "next/server";
import { NextResponse } from "next/server";
import { env } from "~/env";

export const runtime = "edge";

/**
 * Health check endpoint for monitoring services.
 * Requires Bearer token authentication if HEALTH_CHECK_AUTH_TOKEN is set.
 */
export function GET(request: NextRequest) {
  // Check if authentication is configured
  const authToken = env.HEALTH_CHECK_AUTH_TOKEN;

  if (authToken) {
    const authHeader = request.headers.get("authorization");

    if (!authHeader) {
      return NextResponse.json(
        { error: "Authorization required" },
        { status: 401 }
      );
    }

    const bearerRegex = /^Bearer\s+(.+)$/i;
    const bearerMatch = bearerRegex.exec(authHeader);
    if (!bearerMatch?.[1] || bearerMatch[1] !== authToken) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }
  }

  const response = NextResponse.json({
    status: "ok",
    timestamp: new Date().toISOString(),
    service: "console",
    environment: env.NODE_ENV,
  });

  response.headers.set("Cache-Control", "no-store, no-cache, must-revalidate");

  return response;
}

/**
 * Activity Recording Helper Functions
 *
 * Three-tier recording strategy for org user activities:
 *
 * Tier 1 (Synchronous) - recordCriticalActivity()
 *   - For critical operations requiring immediate persistence
 *   - Examples: auth events, permission changes, API key operations
 *   - Impact: +10-30ms latency, 0% data loss
 *
 * Tier 2 (Queue-based) - recordActivity()
 *   - For user-initiated actions with guaranteed delivery
 *   - Examples: workspace edits, integration changes, job restarts
 *   - Impact: +20-50ms latency (event send), 0% data loss
 *   - Processing: Batched by Inngest (up to 100 events, 10s timeout)
 *
 * Tier 3 (Fire-and-forget) - recordSystemActivity()
 *   - For high-volume system events
 *   - Examples: search queries, document processing, webhook deliveries
 *   - Impact: <1ms latency, ~1% data loss acceptable
 *
 * @see /docs/implementation/user-activity-tracking.md
 */

import { db } from "@db/app/client";
import type { InsertOrgUserActivity } from "@db/app/schema";
import { orgUserActivities } from "@db/app/schema";
import type {
  ActivityCategory,
  ActivityMetadata,
  ActivityType,
} from "@repo/app-validation";
import { activityTypeSchema } from "@repo/app-validation";
import { log } from "@vendor/observability/log/next";
import { inngest } from "../inngest/client/client";

/**
 * Activity data interface with validated type information
 *
 * Combines the validated ActivityType fields with additional context
 * needed for recording activities (workspace, actor, entity information).
 *
 * @example
 * ```typescript
 * const data: ActivityData = {
 *   clerkOrgId: "org_abc123",
 *   actorType: "user",
 *   actorUserId: ctx.session.userId,
 *   category: "org",
 *   action: "integration.connected",
 *   entityType: "org",
 *   entityId: "org_xxx",
 *   metadata: {
 *     orgName: "My Org",
 *     clerkOrgId: "org_123",
 *   },
 * };
 * ```
 */
export interface ActivityData {
  /** Action performed - must match one of the defined activity types */
  action: ActivityType["action"];
  /** Activity category */
  category: ActivityCategory;
  /** Org ID */
  clerkOrgId: string;
  /** Entity ID */
  entityId: string;
  /** Entity type */
  entityType: string;
  /** Activity metadata - validated based on action type */
  metadata: ActivityMetadata;
  /** Related activity ID (for grouping) */
  relatedActivityId?: string;
}

/**
 * Tier 1: Record Critical Activity (Synchronous)
 *
 * For operations requiring immediate persistence with 0% data loss.
 * Writes directly to database in the request lifecycle.
 *
 * **Use for:**
 * - Authentication events (login, logout, 2FA)
 * - Permission changes (role assignments, access grants)
 * - API key operations (create, revoke)
 * - Critical workspace changes (deletion, transfer)
 *
 * **Performance:**
 * - Adds 10-30ms to request latency
 * - Guarantees persistence before response
 * - No data loss risk
 *
 * @example
 * ```typescript
 * await recordCriticalActivity({
 *   clerkOrgId: ctx.auth.orgId,
 *   actorType: "user",
 *   actorUserId: ctx.session.userId,
 *   category: "org",
 *   action: "integration.connected",
 *   entityType: "org",
 *   entityId: org.id,
 *   metadata: {
 *     orgSlug: ctx.auth.orgSlug,
 *     clerkOrgId: org.clerkOrgId,
 *   },
 * });
 * ```
 */
export async function recordCriticalActivity(
  data: ActivityData
): Promise<
  { success: true; activityId: number } | { success: false; error: string }
> {
  try {
    // Validate activity type (action, category, metadata)
    const validation = activityTypeSchema.safeParse({
      action: data.action,
      category: data.category,
      metadata: data.metadata,
    });

    if (!validation.success) {
      log.error("Invalid activity data", {
        clerkOrgId: data.clerkOrgId,
        action: data.action,
        errors: validation.error.flatten(),
      });
      return {
        success: false,
        error: `Invalid activity data: ${validation.error.issues.map((e: { message: string }) => e.message).join(", ")}`,
      };
    }

    const [result] = await db
      .insert(orgUserActivities)
      .values({
        clerkOrgId: data.clerkOrgId,
        category: data.category,
        action: data.action,
        entityType: data.entityType,
        entityId: data.entityId,
        metadata: data.metadata,
        relatedActivityId: data.relatedActivityId ?? null,
      })
      .returning({ id: orgUserActivities.id });

    log.info("Critical activity recorded", {
      activityId: result?.id,
      clerkOrgId: data.clerkOrgId,
      category: data.category,
      action: data.action,
    });

    return { success: true, activityId: result?.id ?? 0 };
  } catch (error) {
    log.error("Failed to record critical activity", {
      clerkOrgId: data.clerkOrgId,
      category: data.category,
      action: data.action,
      error: error instanceof Error ? error.message : String(error),
    });

    return {
      success: false,
      error: error instanceof Error ? error.message : "Unknown error",
    };
  }
}

/**
 * Tier 2: Record Activity (Queue-based)
 *
 * For user-initiated actions with guaranteed delivery via Inngest batching.
 * Events are batched per workspace for efficient database writes.
 *
 * **Use for:**
 * - Workspace edits (name, settings)
 * - Integration changes (connect, disconnect, configure)
 * - Job operations (restart, cancel)
 * - Store management (create, delete)
 * - Search queries (user-initiated)
 *
 * **Performance:**
 * - Adds 20-50ms to send event
 * - Batched by Inngest (up to 100 events, 10s timeout)
 * - 50-100x faster than individual inserts
 * - No data loss risk
 *
 * @example
 * ```typescript
 * await recordActivity({
 *   clerkOrgId: ctx.auth.orgId,
 *   actorType: "user",
 *   actorUserId: ctx.session.userId,
 *   category: "org",
 *   action: "org.updated",
 *   entityType: "org",
 *   entityId: clerkOrgId,
 *   metadata: {
 *     changes: {
 *       name: { from: "Old Name", to: "New Name" },
 *     },
 *   },
 * });
 * ```
 */
export async function recordActivity(
  data: ActivityData
): Promise<{ success: true } | { success: false; error: string }> {
  try {
    // Validate activity type (action, category, metadata)
    const validation = activityTypeSchema.safeParse({
      action: data.action,
      category: data.category,
      metadata: data.metadata,
    });

    if (!validation.success) {
      log.error("Invalid activity data", {
        clerkOrgId: data.clerkOrgId,
        action: data.action,
        errors: validation.error.flatten(),
      });
      return {
        success: false,
        error: `Invalid activity data: ${validation.error.issues.map((e: { message: string }) => e.message).join(", ")}`,
      };
    }

    await inngest.send({
      name: "console/activity.record",
      data: {
        clerkOrgId: data.clerkOrgId,
        category: data.category,
        action: data.action,
        entityType: data.entityType,
        entityId: data.entityId,
        metadata: data.metadata,
        relatedActivityId: data.relatedActivityId,
        timestamp: new Date().toISOString(),
      },
    });

    log.debug("Activity event sent", {
      clerkOrgId: data.clerkOrgId,
      category: data.category,
      action: data.action,
    });

    return { success: true };
  } catch (error) {
    log.error("Failed to send activity event", {
      clerkOrgId: data.clerkOrgId,
      category: data.category,
      action: data.action,
      error: error instanceof Error ? error.message : String(error),
    });

    return {
      success: false,
      error: error instanceof Error ? error.message : "Unknown error",
    };
  }
}

/**
 * Tier 3: Record System Activity (Fire-and-forget)
 *
 * For high-volume system events where ~1% data loss is acceptable.
 * Sends event without awaiting confirmation for minimal latency impact.
 *
 * **Use for:**
 * - Document processing events
 * - Webhook deliveries (GitHub, Linear)
 * - System background jobs
 * - High-frequency search queries
 * - Metrics collection
 *
 * **Performance:**
 * - <1ms latency impact
 * - No blocking
 * - ~1% data loss acceptable (network failures, etc.)
 *
 * @example
 * ```typescript
 * recordSystemActivity({
 *   clerkOrgId: clerkOrgId,
 *   actorType: "system",
 *   category: "job",
 *   action: "job.cancelled",
 *   entityType: "job",
 *   entityId: jobId,
 *   metadata: {
 *     jobName: "sync-github-repo",
 *     previousStatus: "running",
 *     inngestFunctionId: "github-sync",
 *   },
 * });
 * ```
 */
export function recordSystemActivity(data: ActivityData): void {
  // Validate activity type (action, category, metadata)
  const validation = activityTypeSchema.safeParse({
    action: data.action,
    category: data.category,
    metadata: data.metadata,
  });

  if (!validation.success) {
    log.error("Invalid system activity data", {
      clerkOrgId: data.clerkOrgId,
      action: data.action,
      errors: validation.error.flatten(),
    });
    return; // Fire-and-forget: don't throw, just log and return
  }

  // Fire-and-forget: don't await, don't block
  inngest
    .send({
      name: "console/activity.record",
      data: {
        clerkOrgId: data.clerkOrgId,
        category: data.category,
        action: data.action,
        entityType: data.entityType,
        entityId: data.entityId,
        metadata: data.metadata,
        relatedActivityId: data.relatedActivityId,
        timestamp: new Date().toISOString(),
      },
    })
    .catch((error) => {
      // Log error but don't throw (fire-and-forget)
      log.warn("System activity event failed (fire-and-forget)", {
        clerkOrgId: data.clerkOrgId,
        category: data.category,
        action: data.action,
        error: error instanceof Error ? error.message : String(error),
      });
    });
}

/**
 * Batch Record Activities (Internal Use)
 *
 * For internal batch operations where you already have multiple activities prepared.
 * Directly inserts into database without going through Inngest.
 *
 * **Use for:**
 * - Data migrations
 * - Bulk imports
 * - Admin operations
 *
 * @internal
 */
export async function batchRecordActivities(
  activities: InsertOrgUserActivity[]
): Promise<{ success: boolean; insertedCount: number; error?: string }> {
  try {
    const result = await db
      .insert(orgUserActivities)
      .values(activities)
      .returning({ id: orgUserActivities.id });

    log.info("Batch activities recorded", {
      insertedCount: result.length,
      requestedCount: activities.length,
    });

    return {
      success: true,
      insertedCount: result.length,
    };
  } catch (error) {
    log.error("Failed to batch record activities", {
      count: activities.length,
      error: error instanceof Error ? error.message : String(error),
    });

    return {
      success: false,
      insertedCount: 0,
      error: error instanceof Error ? error.message : "Unknown error",
    };
  }
}

/**
 * Console-specific Pinecone client wrapper
 *
 * Wraps @vendor/pinecone and injects configuration from @repo/app-config.
 * Provides a convenience API with sensible defaults for the console application.
 */

import type { RecordMetadata } from "@pinecone-database/pinecone";
import { PINECONE_CONFIG } from "@repo/app-config";
import { PineconeClient as VendorPineconeClient } from "@vendor/pinecone/client";
import type {
  FetchResponse,
  QueryRequest,
  QueryResponse,
  UpdateRequest,
  UpsertRequest,
  UpsertResponse,
} from "@vendor/pinecone/types";

/**
 * Console-specific Pinecone client with injected configuration
 *
 * This wrapper provides the same API as @vendor/pinecone but automatically
 * injects private configuration defaults from @repo/app-config.
 */
export class ConsolePineconeClient {
  private readonly client: VendorPineconeClient;

  constructor() {
    this.client = new VendorPineconeClient();
  }

  /**
   * Create index with console configuration defaults
   *
   * Automatically injects:
   * - metric: "cosine"
   * - cloud: "aws"
   * - region: "us-west-2"
   */
  async createIndex(indexName: string, dimension: number): Promise<void> {
    return this.client.createIndex(indexName, dimension, {
      metric: PINECONE_CONFIG.metric,
      cloud: PINECONE_CONFIG.cloud,
      region: PINECONE_CONFIG.region,
    });
  }

  /**
   * Check if a Pinecone index exists
   *
   * @param indexName - Name of the index to check
   * @returns true if index exists, false otherwise
   */
  async indexExists(indexName: string): Promise<boolean> {
    return this.client.indexExists(indexName);
  }

  /**
   * Delete a Pinecone index
   */
  async deleteIndex(indexName: string): Promise<void> {
    return this.client.deleteIndex(indexName);
  }

  /**
   * Upsert vectors with automatic batching based on console config
   *
   * Generic method - works with any metadata type extending RecordMetadata
   *
   * @param indexName - Name of the index
   * @param request - Upsert request with vectors and metadata
   * @param namespace - Optional namespace for data isolation
   */
  async upsertVectors<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    request: UpsertRequest<T>,
    namespace?: string
  ): Promise<UpsertResponse> {
    return this.client.upsertVectors(
      indexName,
      request,
      PINECONE_CONFIG.upsertBatchSize,
      namespace
    );
  }

  /**
   * Delete vectors by IDs
   *
   * @param indexName - Name of the index
   * @param vectorIds - Array of vector IDs to delete
   * @param namespace - Optional namespace for data isolation
   */
  async deleteVectors(
    indexName: string,
    vectorIds: string[],
    namespace?: string
  ): Promise<void> {
    return this.client.deleteVectors(
      indexName,
      vectorIds,
      PINECONE_CONFIG.deleteBatchSize,
      namespace
    );
  }

  /**
   * Delete vectors by metadata filter
   *
   * @param indexName - Name of the index
   * @param filter - Metadata filter object
   * @param namespace - Optional namespace for data isolation
   */
  async deleteByMetadata(
    indexName: string,
    filter: object,
    namespace?: string
  ): Promise<void> {
    return this.client.deleteByMetadata(indexName, filter, namespace);
  }

  /**
   * Query similar vectors
   *
   * Generic method - works with any metadata type extending RecordMetadata
   *
   * @param indexName - Name of the index
   * @param request - Query request with vector and filters
   * @param namespace - Optional namespace for data isolation
   */
  async query<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    request: QueryRequest,
    namespace?: string
  ): Promise<QueryResponse<T>> {
    return this.client.query<T>(indexName, request, namespace);
  }

  /**
   * Configure index level settings (deletion protection, tags, etc.)
   */
  async configureIndex(
    indexName: string,
    options: {
      deletionProtection?: "enabled" | "disabled";
      tags?: Record<string, string>;
      spec?: unknown;
    }
  ): Promise<void> {
    return this.client.configureIndex(indexName, options);
  }

  /**
   * Fetch vectors by IDs
   *
   * Generic method - works with any metadata type extending RecordMetadata
   *
   * @param indexName - Name of the index
   * @param vectorIds - Array of vector IDs to fetch
   * @param namespace - Optional namespace for data isolation
   */
  async fetchVectors<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    vectorIds: string[],
    namespace?: string
  ): Promise<FetchResponse<T>> {
    return this.client.fetchVectors<T>(indexName, vectorIds, namespace);
  }

  /**
   * Update a vector's metadata
   *
   * Generic method - works with any metadata type extending RecordMetadata
   *
   * @param indexName - Name of the index
   * @param request - Update request with vector ID and metadata
   * @param namespace - Optional namespace for data isolation
   */
  async updateVectorMetadata<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    request: UpdateRequest<T>,
    namespace?: string
  ): Promise<void> {
    return this.client.updateVectorMetadata(indexName, request, namespace);
  }
}

/**
 * Create a new console Pinecone client instance
 */
export function createConsolePineconeClient(): ConsolePineconeClient {
  return new ConsolePineconeClient();
}

/**
 * Default console Pinecone client instance
 *
 * Use this for most operations unless you need a custom instance.
 */
export const consolePineconeClient = new ConsolePineconeClient();

/**
 * @repo/app-pinecone
 *
 * Console-specific Pinecone utilities with typed vector metadata.
 * Uses @vendor/pinecone for core Pinecone functionality.
 *
 * @packageDocumentation
 */

// Re-export types from vendor/pinecone
export type {
  FetchedRecord,
  FetchResponse,
  QueryMatch,
  QueryRequest,
  QueryResponse,
  UpdateRequest,
  UpsertRequest,
  UpsertResponse,
} from "@vendor/pinecone/types";
// Export console-specific client with injected config
// Alias for backwards compatibility
export {
  ConsolePineconeClient,
  consolePineconeClient,
  consolePineconeClient as pineconeClient,
  createConsolePineconeClient,
} from "./client";

/**
 * Console Clerk M2M Package
 *
 * Machine-to-Machine authentication for the Console application using Clerk.
 * This package provides M2M token management and verification for internal services.
 *
 * @example
 * ```typescript
 * import { getM2MToken, verifyM2MToken, isM2MConfigured } from "@repo/app-clerk-m2m";
 *
 * // Get token for a service
 * const token = getM2MToken("webhook");
 *
 * // Verify incoming token
 * const verified = await verifyM2MToken(token);
 *
 * // Check if M2M is configured
 * if (isM2MConfigured("webhook")) {
 *   // Use M2M auth
 * }
 * ```
 */

export { consoleM2MEnv } from "./env";
export {
  createM2MToken,
  isM2MConfigured,
  type M2MService,
  verifyM2MToken,
} from "./m2m";

/**
 * API Key cryptographic utilities
 *
 * Provides functions for:
 * - Generating API keys with the correct format
 * - Hashing keys using SHA-256
 * - Extracting key previews for display
 */

import { sha256Hex } from "@repo/app-providers";
import { nanoid } from "@repo/lib";

/**
 * Unified API key prefix for all Lightfast keys
 * Format follows industry conventions: sk-{vendor}-{secret}
 */
export const LIGHTFAST_API_KEY_PREFIX = "sk-lf-";

/**
 * Length of the random portion of the API key
 * 43 chars × 62-char alphabet = ~256 bits entropy
 */
export const API_KEY_SECRET_LENGTH = 43;

/**
 * Number of characters to show in the key preview
 */
export const API_KEY_PREVIEW_LENGTH = 4;

/**
 * @deprecated Legacy prefix - do not use for new keys
 */
export const API_KEY_PREFIX = "console_sk_";

/**
 * Generate a new API key with the unified Lightfast format
 *
 * @param prefix - The prefix to use (default: "sk-lf-")
 * @returns The generated API key with ~256 bits of entropy
 *
 * @example
 * ```ts
 * const key = generateApiKey();  // "sk-lf-AbC123xYz456..."
 * ```
 */
export function generateApiKey(
  prefix: string = LIGHTFAST_API_KEY_PREFIX
): string {
  const keySecret = nanoid(API_KEY_SECRET_LENGTH);
  return `${prefix}${keySecret}`;
}

/**
 * Result from generateOrgApiKey containing all parts needed for storage
 */
export interface OrgApiKeyResult {
  /** Full API key (only returned once, never stored) */
  key: string;
  /** Key prefix (e.g., "sk-lf-") */
  prefix: string;
  /** Last 4 characters of the key secret (for display) */
  suffix: string;
}

/**
 * Generate a new organization API key, returning all parts for storage
 *
 * This is used for org-scoped API keys where we store
 * the prefix and suffix separately for display purposes.
 *
 * @returns Object with full key, prefix, and suffix (last 4 chars)
 *
 * @example
 * ```ts
 * const { key, prefix, suffix } = generateOrgApiKey();
 * // key: "REDACTED" (full key - return once)
 * // prefix: "sk-lf-"
 * // suffix: "Z789" (last 4 chars)
 * ```
 */
export function generateOrgApiKey(): OrgApiKeyResult {
  const keySecret = nanoid(API_KEY_SECRET_LENGTH);
  const key = `${LIGHTFAST_API_KEY_PREFIX}${keySecret}`;
  const suffix = keySecret.slice(-API_KEY_PREVIEW_LENGTH);

  return {
    key,
    prefix: LIGHTFAST_API_KEY_PREFIX,
    suffix,
  };
}

/**
 * Hash an API key using SHA-256
 *
 * This is used to:
 * - Store the key hash in the database (never store plaintext)
 * - Verify incoming keys by hashing and comparing
 *
 * @param key - The API key to hash
 * @returns Hex-encoded SHA-256 hash of the key
 *
 * @example
 * ```ts
 * const hash = hashApiKey("sk-lf-abc123...");
 * // Returns: "abc123...def456" (64 character hex string)
 * ```
 */
export function hashApiKey(key: string): string {
  return sha256Hex(key);
}

/**
 * Extract a preview of the API key for display purposes
 *
 * @param key - The full API key
 * @returns Preview string in format "sk-lf-...XXXX"
 */
export function extractKeyPreview(key: string): string {
  const suffix = key.slice(-API_KEY_PREVIEW_LENGTH);
  return `sk-lf-...${suffix}`;
}

/**
 * Validate that a string has the correct API key format
 *
 * @param key - The string to validate
 * @returns True if the key has the correct format
 */
export function isValidApiKeyFormat(key: string): boolean {
  // Must start with sk-lf-
  if (!key.startsWith(LIGHTFAST_API_KEY_PREFIX)) {
    return false;
  }

  // Must have correct length: prefix (6) + secret (43) = 49
  const expectedLength =
    LIGHTFAST_API_KEY_PREFIX.length + API_KEY_SECRET_LENGTH;
  return key.length === expectedLength;
}

