1	/**
2	 * Memory service tRPC initialization.
3	 *
4	 * Auth model: service-to-service JWT (not Clerk).
5	 * All callers are internal services (console, platform, inngest, cron).
6	 */
7	import { nanoid } from "@repo/lib";
8	import { trpcMiddleware } from "@sentry/core";
9	import { initTRPC, TRPCError } from "@trpc/server";
10	import { log } from "@vendor/observability/log/next";
11	import { emitJournal, withRequestContext } from "@vendor/observability/request";
12	import superjson from "superjson";
13	import { ZodError } from "zod";
14	
15	import { verifyServiceJWT } from "./lib/jwt";
16	
17	// -- Auth Context -------------------------------------------------------------
18	
19	/**
20	 * Discriminated union for memory service authentication.
21	 * Every request resolves to exactly one variant.
22	 */
23	export type MemoryAuthContext =
24	  | { type: "service"; caller: string }
25	  | { type: "webhook"; provider: string }
26	  | { type: "inngest" }
27	  | { type: "cron" }
28	  | { type: "unauthenticated" };
29	
30	// -- Context Creation ---------------------------------------------------------
31	
32	/**
33	 * Create tRPC context for memory service requests.
34	 *
35	 * Auth resolution order:
36	 * 1. Bearer JWT in Authorization header -> service auth
37	 * 2. X-Memory-Source header for internal identification
38	 * 3. Unauthenticated fallback
39	 */
40	export const createMemoryTRPCContext = async (opts: { headers: Headers }) => {
41	  const source = opts.headers.get("x-trpc-source") ?? "unknown";
42	
43	  // Check for service JWT in Authorization header
44	  const authHeader = opts.headers.get("authorization");
45	  if (authHeader?.startsWith("Bearer ")) {
46	    const token = authHeader.replace("Bearer ", "");
47	
48	    try {
49	      const verified = await verifyServiceJWT(token);
50	      log.info("[trpc] memory service request", {
51	        source,
52	        auth: "service",
53	        caller: verified.caller,
54	      });
55	      return {
56	        auth: {
57	          type: "service" as const,
58	          caller: verified.caller,
59	        },
60	        headers: opts.headers,
61	      };
62	    } catch (error) {
63	      log.warn("[trpc] JWT verification error", {
64	        source,
65	        error: error instanceof Error ? error.message : String(error),
66	      });
67	    }
68	  }
69	
70	  // No authentication
71	  log.info("[trpc] memory service request", {
72	    source,
73	    auth: "unauthenticated",
74	  });
75	  return {
76	    auth: { type: "unauthenticated" as const },
77	    headers: opts.headers,
78	  };
79	};
80	
81	// -- tRPC Initialization ------------------------------------------------------
82	
83	const isProduction = process.env.NODE_ENV === "production";
84	
85	const t = initTRPC.context<typeof createMemoryTRPCContext>().create({
86	  transformer: superjson,
87	  errorFormatter: ({ shape, error }) => {
88	    const shouldSanitize =
89	      isProduction && error.code === "INTERNAL_SERVER_ERROR";
90	
91	    return {
92	      ...shape,
93	      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
94	      data: {
95	        ...shape.data,
96	        zodError:
97	          error.cause instanceof ZodError ? error.cause.flatten() : null,
98	      },
99	    };
100	  },
101	});
102	
103	// -- Middleware ----------------------------------------------------------------
104	
105	const sentryMiddleware = t.middleware(
106	  trpcMiddleware({
107	    attachRpcInput: true,
108	  }),
109	);
110	
111	const sentrifiedProcedure = t.procedure.use(sentryMiddleware);
112	
113	const observabilityMiddleware = t.middleware(
114	  async ({ next, path, ctx, type }) => {
115	    if (t._config.isDev) {
116	      const waitMs = Math.floor(Math.random() * 400) + 100;
117	      await new Promise((resolve) => setTimeout(resolve, waitMs));
118	    }
119	
120	    const { result, journal, durationMs } = await withRequestContext(
121	      {
122	        requestId: nanoid(),
123	        ...(ctx.auth.type === "service" && { caller: ctx.auth.caller }),
124	      },
125	      () => next(),
126	    );
127	
128	    const meta = {
129	      path,
130	      type,
131	      durationMs,
132	      ok: result.ok,
133	      ...(!result.ok && { errorCode: result.error?.code }),
134	      ...(ctx.auth.type === "service" && { caller: ctx.auth.caller }),
135	    };
136	
137	    if (result.ok) {
138	      log.info("[trpc] procedure completed", meta);
139	    } else {
140	      log.warn("[trpc] procedure failed", meta);
141	    }
142	
143	    emitJournal(journal, { path, durationMs, ok: result.ok });
144	
145	    return result;
146	  },
147	);
148	
149	// -- Router & Procedure Exports -----------------------------------------------
150	
151	export const createTRPCRouter = t.router;
152	export const createCallerFactory = t.createCallerFactory;
153	
154	/**
155	 * Public procedure -- no auth required.
156	 * Use for health checks or publicly accessible endpoints.
157	 */
158	export const publicProcedure = sentrifiedProcedure.use(observabilityMiddleware);
159	
160	/**
161	 * Service procedure -- requires valid service JWT.
162	 * Used by console, platform, or other internal services calling memory.
163	 *
164	 * Guarantees `ctx.auth.type === "service"` and `ctx.auth.caller` is available.
165	 */
166	export const serviceProcedure = sentrifiedProcedure
167	  .use(observabilityMiddleware)
168	  .use(({ ctx, next }) => {
169	    if (ctx.auth.type !== "service") {
170	      throw new TRPCError({
171	        code: "UNAUTHORIZED",
172	        message:
173	          "Service authentication required. Provide a valid service JWT in the Authorization header.",
174	      });
175	    }
176	
177	    return next({
178	      ctx: {
179	        ...ctx,
180	        auth: ctx.auth as Extract<MemoryAuthContext, { type: "service" }>,
181	      },
182	    });
183	  });
184	
185	/**
186	 * Admin procedure -- requires service JWT from an admin caller.
187	 * Used for administrative operations (reindex, purge, etc.).
188	 *
189	 * Restricts `ctx.auth.caller` to "admin" only.
190	 */
191	export const adminProcedure = sentrifiedProcedure
192	  .use(observabilityMiddleware)
193	  .use(({ ctx, next }) => {
194	    if (ctx.auth.type !== "service") {
195	      throw new TRPCError({
196	        code: "UNAUTHORIZED",
197	        message: "Service authentication required.",
198	      });
199	    }
200	
201	    if (ctx.auth.caller !== "admin") {
202	      throw new TRPCError({
203	        code: "FORBIDDEN",
204	        message:
205	          "Admin access required. This endpoint is restricted to admin callers.",
206	      });
207	    }
208	
209	    return next({
210	      ctx: {
211	        ...ctx,
212	        auth: ctx.auth as Extract<MemoryAuthContext, { type: "service" }>,
213	      },
214	    });
215	  });
