1	/**
2	 * Clerk Machine-to-Machine (M2M) Authentication for Console App
3	 *
4	 * Provides Clerk's M2M token system for server-to-server authentication.
5	 * Uses long-lived tokens (365-day expiration) created once in Clerk Dashboard.
6	 *
7	 * Architecture:
8	 * - tRPC Machine (receiver): Verifies ALL incoming M2M tokens using its secret key
9	 * - Webhook Machine (sender): Sends pre-created token to authenticate with tRPC
10	 * - Inngest Machine (sender): Sends pre-created token to authenticate with tRPC
11	 *
12	 * One-Time Setup in Clerk Dashboard:
13	 * 1. Create 3 machines: "tRPC API", "Webhook Handler", "Inngest Workflows"
14	 * 2. Configure scopes:
15	 *    - Webhook Handler can communicate with tRPC API
16	 *    - Inngest Workflows can communicate with tRPC API
17	 *    - tRPC API can communicate with both
18	 * 3. Generate long-lived tokens (365 days):
19	 *    - From Webhook Handler machine → Copy token (mt_xxx) and machine ID (mch_xxx)
20	 *    - From Inngest Workflows machine → Copy token (mt_xxx) and machine ID (mch_xxx)
21	 * 4. Store in environment:
22	 *    - CLERK_MACHINE_SECRET_KEY_TRPC (tRPC's secret to verify all tokens)
23	 *    - CLERK_M2M_TOKEN_WEBHOOK (webhook's pre-created token)
24	 *    - CLERK_M2M_MACHINE_ID_WEBHOOK (webhook's machine ID for validation)
25	 *    - CLERK_M2M_TOKEN_INNGEST (inngest's pre-created token)
26	 *    - CLERK_M2M_MACHINE_ID_INNGEST (inngest's machine ID for validation)
27	 *
28	 * How it works:
29	 * 1. Webhook/Inngest sends request with their pre-created token in Authorization header
30	 * 2. tRPC verifies token using CLERK_MACHINE_SECRET_KEY_TRPC
31	 * 3. tRPC checks verified.subject matches expected machine ID
32	 *
33	 * @see https://clerk.com/docs/machine-auth/m2m-tokens
34	 */
35	
36	import { createClerkClient } from "@vendor/clerk/backend";
37	import { consoleM2MEnv } from "./env";
38	
39	/**
40	 * Service types for M2M authentication
41	 * Each sender service creates tokens on-demand
42	 */
43	export type M2MService = "webhook" | "inngest";
44	
45	/**
46	 * Get machine secret key for a specific service
47	 * Helper function to retrieve the correct secret key based on service type
48	 *
49	 * @param service - Which service to get the key for
50	 * @returns The machine secret key for the service
51	 * @throws {Error} If service is unknown
52	 */
53	function getMachineSecretKey(service: M2MService): string {
54	  if (service === "webhook") {
55	    return consoleM2MEnv.CLERK_MACHINE_SECRET_KEY_WEBHOOK;
56	  }
57	  if (service === "inngest") {
58	    return consoleM2MEnv.CLERK_MACHINE_SECRET_KEY_INNGEST;
59	  }
60	  throw new Error(`Unknown M2M service: ${service}`);
61	}
62	
63	/**
64	 * Create M2M token on-demand for a specific service
65	 *
66	 * Creates a short-lived token (30 seconds) for security.
67	 * Follows Clerk's recommended pattern of creating tokens per request.
68	 *
69	 * @param service - Which service is creating the token
70	 * @returns The M2M token object with token and expiration
71	 *
72	 * @example
73	 * ```typescript
74	 * // For webhook handlers
75	 * const { token } = await createM2MToken("webhook");
76	 * headers.set("authorization", `Bearer ${token}`);
77	 *
78	 * // For Inngest workflows
79	 * const { token } = await createM2MToken("inngest");
80	 * headers.set("authorization", `Bearer ${token}`);
81	 * ```
82	 */
83	export async function createM2MToken(service: M2MService): Promise<{
84	  token: string;
85	  expiration: number;
86	}> {
87	  // Get the machine secret key for this service
88	  const machineSecretKey = getMachineSecretKey(service);
89	
90	  console.log(
91	    `[M2M] Creating token for ${service} with secret: ${machineSecretKey.substring(0, 10)}...`
92	  );
93	
94	  // Create a Clerk client with this machine's secret key
95	  const clerk = createClerkClient({
96	    secretKey: machineSecretKey,
97	  });
98	
99	  // Create a short-lived token (30 seconds)
100	  // This is more secure than long-lived tokens
101	  const m2mObject = await clerk.m2m.createToken({
102	    secondsUntilExpiration: 30,
103	  });
104	
105	  if (!m2mObject.token) {
106	    throw new Error(
107	      `[M2M] Failed to create token for ${service}: token is undefined`
108	    );
109	  }
110	
111	  console.log(
112	    `[M2M] Created token: ${m2mObject.token.substring(0, 10)}... (expires in 30s)`
113	  );
114	
115	  return {
116	    token: m2mObject.token,
117	    expiration: m2mObject.expiration ?? 0,
118	  };
119	}
120	
121	/**
122	 * Verify M2M token from incoming request
123	 *
124	 * Uses the tRPC machine secret to verify ALL incoming M2M tokens.
125	 * The `subject` field in the response identifies which machine created the token.
126	 *
127	 * Validates that the token:
128	 * - Was created by an authorized machine (webhook or inngest)
129	 * - Has not been revoked
130	 * - Has not expired
131	 *
132	 * @param token - The token string from Authorization header (without "Bearer " prefix)
133	 * @returns Token verification result with subject (machine ID that created token)
134	 * @throws {Error} If token is invalid, revoked, or expired
135	 *
136	 * @example
137	 * ```typescript
138	 * // In tRPC context
139	 * const authHeader = request.headers.get("authorization");
140	 * const token = authHeader?.replace("Bearer ", "");
141	 * const verified = await verifyM2MToken(token);
142	 *
143	 * if (verified.expired || verified.revoked) {
144	 *   throw new Error("Invalid token");
145	 * }
146	 *
147	 * // Check which machine sent the request
148	 * console.log("Request from machine:", verified.subject);
149	 * ```
150	 */
151	export async function verifyM2MToken(token: string): Promise<{
152	  id: string;
153	  subject: string; // Machine ID that created the token (webhook or inngest machine)
154	  scopes: string[]; // Allowed machine IDs this token can communicate with
155	  claims: Record<string, unknown> | null;
156	  revoked: boolean;
157	  expired: boolean;
158	  expiration: number | null;
159	}> {
160	  // Use the tRPC machine secret to verify ALL incoming tokens
161	  // Following Clerk's example pattern exactly
162	  const machineSecretKey = consoleM2MEnv.CLERK_MACHINE_SECRET_KEY_TRPC;
163	
164	  console.log("[M2M] Verifying token with tRPC machine secret");
165	  console.log(`[M2M] Token prefix: ${token.substring(0, 10)}...`);
166	  console.log(
167	    `[M2M] Machine secret prefix: ${machineSecretKey.substring(0, 10)}...`
168	  );
169	
170	  // Create a Clerk client with the tRPC machine's secret key
171	  // This allows it to verify tokens created by webhook/inngest machines
172	  const clerk = createClerkClient({
173	    secretKey: machineSecretKey,
174	  });
175	
176	  // Verify token using Clerk's M2M API
177	  // No need to pass machineSecretKey - it's already in the client
178	  const verified = await clerk.m2m.verify({
179	    token,
180	  });
181	
182	  console.log(`[M2M] Token verified. Created by machine: ${verified.subject}`);
183	
184	  return {
185	    id: verified.id,
186	    subject: verified.subject, // Machine ID that created the token
187	    scopes: verified.scopes, // Allowed machine IDs
188	    claims: verified.claims,
189	    revoked: verified.revoked,
190	    expired: verified.expired,
191	    expiration: verified.expiration,
192	  };
193	}
194	
195	/**
196	 * Check if M2M is configured for a specific service
197	 * Useful for conditional logic or graceful degradation
198	 *
199	 * Checks:
200	 * - Service has a machine secret key (CLERK_MACHINE_SECRET_KEY_WEBHOOK or CLERK_MACHINE_SECRET_KEY_INNGEST)
201	 * - tRPC has machine secret to verify (CLERK_MACHINE_SECRET_KEY_TRPC)
202	 *
203	 * @param service - Which service to check
204	 * @returns true if service secret key and tRPC machine secret are configured
205	 *
206	 * @example
207	 * ```typescript
208	 * if (isM2MConfigured("webhook")) {
209	 *   const caller = await createWebhookCaller();
210	 * } else {
211	 *   // Fallback to legacy auth
212	 * }
213	 * ```
214	 */
215	export function isM2MConfigured(service: M2MService): boolean {
216	  try {
217	    const secretKey = getMachineSecretKey(service);
218	    const trpcSecretKey = consoleM2MEnv.CLERK_MACHINE_SECRET_KEY_TRPC;
219	    return (
220	      !!secretKey &&
221	      secretKey.startsWith("ak_") &&
222	      !!trpcSecretKey &&
223	      trpcSecretKey.startsWith("ak_")
224	    );
225	  } catch {
226	    return false;
227	  }
228	}
