1	/**
2	 * Process OAuth callback — the heavyweight OAuth completion logic.
3	 *
4	 * Ported from apps/gateway/src/routes/connections.ts (lines 208-489).
5	 * Returns structured CallbackProcessResult instead of HTTP responses.
6	 * The Route Handler maps CallbackProcessResult to NextResponse.redirect / HTML.
7	 */
8	import { db } from "@db/app/client";
9	import { gatewayInstallations } from "@db/app/schema";
10	import type { SourceType } from "@repo/app-providers";
11	import { getProvider, providerAccountInfoSchema } from "@repo/app-providers";
12	import { and, eq } from "@vendor/db";
13	import { log } from "@vendor/observability/log/next";
14	import { providerConfigs } from "../provider-configs";
15	import { writeTokenRecord } from "../token-store";
16	import { consumeOAuthState, storeOAuthResult } from "./state";
17	
18	// ── Console URL ──
19	
20	/**
21	 * Console URL for redirects. Mirrors the gateway's consoleUrl logic.
22	 */
23	const consoleUrl = (() => {
24	  const vercelEnv = process.env.VERCEL_ENV;
25	  const vercelUrl = process.env.VERCEL_URL;
26	  const productionUrl = process.env.VERCEL_PROJECT_PRODUCTION_URL;
27	
28	  if (vercelEnv === "preview" && vercelUrl) {
29	    return `https://${vercelUrl}`;
30	  }
31	
32	  if (productionUrl) {
33	    return `https://${productionUrl}`;
34	  }
35	
36	  return "http://localhost:3024";
37	})();
38	
39	// ── Result Types ──
40	
41	/**
42	 * Structured result from processing an OAuth callback.
43	 * The Route Handler maps this to NextResponse.redirect() or HTML response.
44	 */
45	export type CallbackProcessResult =
46	  | { kind: "redirect"; url: string }
47	  | { kind: "inline_html"; html: string; status?: number }
48	  | { kind: "error"; error: string; status: number };
49	
50	// ── Inline HTML Templates ──
51	
52	function successHtml(providerName: string): string {
53	  return `<!doctype html>
54	<html>
55	  <head><title>Connected</title></head>
56	  <body style="font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;background:#fafafa">
57	    <div style="text-align:center">
58	      <div style="font-size:48px;margin-bottom:16px">&#10003;</div>
59	      <h1 style="margin:0 0 8px">Connected to ${providerName}!</h1>
60	      <p style="color:#666">You can close this tab and return to your terminal.</p>
61	    </div>
62	    <script>setTimeout(()=>window.close(),2000)</script>
63	  </body>
64	</html>`;
65	}
66	
67	function errorHtml(message: string): string {
68	  return `<!doctype html>
69	<html>
70	  <head><title>Connection Failed</title></head>
71	  <body style="font-family:system-ui;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;background:#fafafa">
72	    <div style="text-align:center">
73	      <div style="font-size:48px;margin-bottom:16px">&#10007;</div>
74	      <h1 style="margin:0 0 8px">Connection Failed</h1>
75	      <p style="color:#666">${message}</p>
76	      <p style="color:#999;font-size:14px">Close this tab and try again in your terminal.</p>
77	    </div>
78	  </body>
79	</html>`;
80	}
81	
82	// ── Redirect Helpers ──
83	
84	function buildRedirectForCompletion(
85	  stateData: Record<string, string>,
86	  providerName: SourceType,
87	  opts: { reactivated?: boolean; setupAction?: string }
88	): CallbackProcessResult {
89	  const redirectTo = stateData.redirectTo;
90	
91	  if (redirectTo === "inline") {
92	    return { kind: "inline_html", html: successHtml(providerName) };
93	  }
94	
95	  if (redirectTo) {
96	    const redirectUrl = new URL(redirectTo);
97	    if (opts.reactivated) {
98	      redirectUrl.searchParams.set("reactivated", "true");
99	    }
100	    if (opts.setupAction) {
101	      redirectUrl.searchParams.set("setup_action", opts.setupAction);
102	    }
103	    return { kind: "redirect", url: redirectUrl.toString() };
104	  }
105	
106	  // Default: redirect to console (existing behavior, backwards compatible)
107	  const redirectUrl = new URL(
108	    `${consoleUrl}/provider/${providerName}/connected`
109	  );
110	  if (opts.reactivated) {
111	    redirectUrl.searchParams.set("reactivated", "true");
112	  }
113	  if (opts.setupAction) {
114	    redirectUrl.searchParams.set("setup_action", opts.setupAction);
115	  }
116	  return { kind: "redirect", url: redirectUrl.toString() };
117	}
118	
119	function buildRedirectForError(
120	  stateData: Record<string, string>,
121	  providerName: SourceType,
122	  message: string
123	): CallbackProcessResult {
124	  const redirectTo = stateData.redirectTo;
125	
126	  if (redirectTo === "inline") {
127	    return { kind: "inline_html", html: errorHtml(message), status: 400 };
128	  }
129	
130	  if (redirectTo) {
131	    return {
132	      kind: "redirect",
133	      url: `${redirectTo}?error=${encodeURIComponent(message)}`,
134	    };
135	  }
136	
137	  return {
138	    kind: "redirect",
139	    url: `${consoleUrl}/provider/${providerName}/connected?error=${encodeURIComponent(message)}`,
140	  };
141	}
142	
143	// ── Main Callback Processing ──
144	
145	export interface ProcessCallbackParams {
146	  provider: SourceType;
147	  /** All query params from the callback URL */
148	  query: Record<string, string>;
149	  /** The state token from the callback query string */
150	  state: string;
151	}
152	
153	/**
154	 * Process an OAuth callback: validate state, exchange code, upsert installation,
155	 * persist tokens, and return a structured result for the Route Handler to act on.
156	 */
157	export async function processOAuthCallback(
158	  params: ProcessCallbackParams
159	): Promise<CallbackProcessResult> {
160	  const { provider: providerName, state, query } = params;
161	
162	  const providerDef = getProvider(providerName);
163	  const config = providerConfigs[providerName];
164	
165	  if (!config) {
166	    log.warn("[oauth/callback] provider not configured", {
167	      provider: providerName,
168	    });
169	    return {
170	      kind: "error",
171	      error: "unknown_provider",
172	      status: 400,
173	    };
174	  }
175	
176	  let stateData = await consumeOAuthState(state);
177	
178	  // GitHub-initiated redirects (permission changes, reinstalls) arrive without
179	  // our state token. If state is missing but installation_id is present, look up
180	  // the existing installation to recover orgId/connectedBy.
181	  if (!stateData && providerName === "github") {
182	    const installationId = query.installation_id;
183	    if (installationId) {
184	      const existing = await db
185	        .select({
186	          orgId: gatewayInstallations.orgId,
187	          connectedBy: gatewayInstallations.connectedBy,
188	        })
189	        .from(gatewayInstallations)
190	        .where(
191	          and(
192	            eq(gatewayInstallations.provider, "github"),
193	            eq(gatewayInstallations.externalId, installationId)
194	          )
195	        )
196	        .limit(1);
197	
198	      const row = existing[0];
199	      if (row) {
200	        stateData = {
201	          provider: "github",
202	          orgId: row.orgId,
203	          connectedBy: row.connectedBy,
204	        };
205	      }
206	    }
207	  }
208	
209	  if (!stateData) {
210	    log.warn("[oauth/callback] invalid or expired state", {
211	      provider: providerName,
212	      state: state ? `${state.slice(0, 8)}...` : "empty",
213	    });
214	    return {
215	      kind: "error",
216	      error: "invalid_or_expired_state",
217	      status: 400,
218	    };
219	  }
220	
221	  if (stateData.provider !== providerName) {
222	    log.warn("[oauth/callback] state provider mismatch", {
223	      provider: providerName,
224	      stateProvider: stateData.provider,
225	    });
226	    return {
227	      kind: "error",
228	      error: "invalid_or_expired_state",
229	      status: 400,
230	    };
231	  }
232	
233	  const orgId = stateData.orgId ?? "";
234	  const connectedBy = stateData.connectedBy ?? "unknown";
235	
236	  try {
237	    const auth = providerDef.auth;
238	    if (auth.kind !== "oauth" && auth.kind !== "app-token") {
239	      log.warn("[oauth/callback] provider does not support OAuth callback", {
240	        provider: providerName,
241	        authKind: auth.kind,
242	      });
243	      return {
244	        kind: "error",
245	        error: "provider_does_not_support_oauth",
246	        status: 400,
247	      };
248	    }
249	
250	    // Pure provider logic — no DB, no framework coupling.
251	    // Both OAuthDef and AppTokenDef have processCallback — TypeScript narrows here.
252	    // SAFETY: config is providerConfigs[providerName], created by the same provider's
253	    // createConfig(). Runtime type matches TConfig; the service cannot know TConfig
254	    // statically because it serves all providers from a single Record<string, unknown>.
255	    const result = await auth.processCallback(config as never, query);
256	
257	    // Handle pending-setup: provider needs additional configuration (e.g., GitHub App request flow).
258	    // No installation to upsert — just store the setup action and redirect.
259	    if (result.status === "pending-setup") {
260	      await storeOAuthResult(state, {
261	        status: "completed",
262	        provider: providerName,
263	        setupAction: result.setupAction,
264	      });
265	
266	      log.info("[oauth/callback] pending setup, redirecting", {
267	        provider: providerName,
268	        setupAction: result.setupAction,
269	      });
270	      return buildRedirectForCompletion(stateData, providerName, {
271	        setupAction: result.setupAction,
272	      });
273	    }
274	
275	    // For all connected statuses: detect reactivation and upsert installation
276	    const existingRows = await db
277	      .select({ id: gatewayInstallations.id })
278	      .from(gatewayInstallations)
279	      .where(
280	        and(
281	          eq(gatewayInstallations.provider, providerName),
282	          eq(gatewayInstallations.externalId, result.externalId)
283	        )
284	      )
285	      .limit(1);
286	
287	    const reactivated = existingRows.length > 0;
288	
289	    // Parse through schema to validate and narrow to ProviderAccountInfo
290	    // (processCallback returns BaseProviderAccountInfo at the type level when
291	    // called through the union — schema parse gives us the concrete discriminated type)
292	    const accountInfo = providerAccountInfoSchema.parse(result.accountInfo);
293	
294	    // Upsert installation — idempotent on (provider, externalId)
295	    const rows = await db
296	      .insert(gatewayInstallations)
297	      .values({
298	        provider: providerName,
299	        externalId: result.externalId,
300	        connectedBy,
301	        orgId,
302	        status: "active",
303	        providerAccountInfo: accountInfo,
304	      })
305	      .onConflictDoUpdate({
306	        target: [
