import type { NextRequest } from "next/server";
import { NextResponse } from "next/server";
import { env } from "~/env";

export const runtime = "edge";

/**
 * Health check endpoint for monitoring services.
 * Requires Bearer token authentication if HEALTH_CHECK_AUTH_TOKEN is set.
 */
export function GET(request: NextRequest) {
  // Check if authentication is configured
  const authToken = env.HEALTH_CHECK_AUTH_TOKEN;

  if (authToken) {
    const authHeader = request.headers.get("authorization");

    if (!authHeader) {
      return NextResponse.json(
        { error: "Authorization required" },
        { status: 401 }
      );
    }

    const bearerRegex = /^Bearer\s+(.+)$/i;
    const bearerMatch = bearerRegex.exec(authHeader);
    if (!bearerMatch?.[1] || bearerMatch[1] !== authToken) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }
  }

  const response = NextResponse.json({
    status: "ok",
    timestamp: new Date().toISOString(),
    service: "console",
    environment: env.NODE_ENV,
  });

  response.headers.set("Cache-Control", "no-store, no-cache, must-revalidate");

  return response;
}

{
  "name": "@repo/app-reserved-names",
  "version": "0.1.0",
  "private": true,
  "description": "Reserved workspace names for Lightfast Console to prevent URL routing conflicts",
  "license": "FSL-1.1-Apache-2.0",
  "type": "module",
  "exports": {
    ".": {
      "types": "./src/index.ts",
      "default": "./src/index.ts"
    },
    "./organization": {
      "types": "./src/organization.ts",
      "default": "./src/organization.ts"
    }
  },
  "files": [
    "dist",
    "data"
  ],
  "scripts": {
    "clean": "git clean -xdf .cache .turbo node_modules",
    "typecheck": "tsc --noEmit"
  },
  "keywords": [
    "lightfast",
    "reserved",
    "workspace",
    "organization",
    "validation"
  ],
  "devDependencies": {
    "@repo/typescript-config": "workspace:*",
    "typescript": "catalog:"
  }
}

/**
 * Memory service tRPC initialization.
 *
 * Auth model: service-to-service JWT (not Clerk).
 * All callers are internal services (console, platform, inngest, cron).
 */
import { nanoid } from "@repo/lib";
import { trpcMiddleware } from "@sentry/core";
import { initTRPC, TRPCError } from "@trpc/server";
import { log } from "@vendor/observability/log/next";
import { emitJournal, withRequestContext } from "@vendor/observability/request";
import superjson from "superjson";
import { ZodError } from "zod";

import { verifyServiceJWT } from "./lib/jwt";

// -- Auth Context -------------------------------------------------------------

/**
 * Discriminated union for memory service authentication.
 * Every request resolves to exactly one variant.
 */
export type MemoryAuthContext =
  | { type: "service"; caller: string }
  | { type: "webhook"; provider: string }
  | { type: "inngest" }
  | { type: "cron" }
  | { type: "unauthenticated" };

// -- Context Creation ---------------------------------------------------------

/**
 * Create tRPC context for memory service requests.
 *
 * Auth resolution order:
 * 1. Bearer JWT in Authorization header -> service auth
 * 2. X-Memory-Source header for internal identification
 * 3. Unauthenticated fallback
 */
export const createMemoryTRPCContext = async (opts: { headers: Headers }) => {
  const source = opts.headers.get("x-trpc-source") ?? "unknown";

  // Check for service JWT in Authorization header
  const authHeader = opts.headers.get("authorization");
  if (authHeader?.startsWith("Bearer ")) {
    const token = authHeader.replace("Bearer ", "");

    try {
      const verified = await verifyServiceJWT(token);
      log.info("[trpc] memory service request", {
        source,
        auth: "service",
        caller: verified.caller,
      });
      return {
        auth: {
          type: "service" as const,
          caller: verified.caller,
        },
        headers: opts.headers,
      };
    } catch (error) {
      log.warn("[trpc] JWT verification error", {
        source,
        error: error instanceof Error ? error.message : String(error),
      });
    }
  }

  // No authentication
  log.info("[trpc] memory service request", {
    source,
    auth: "unauthenticated",
  });
  return {
    auth: { type: "unauthenticated" as const },
    headers: opts.headers,
  };
};

// -- tRPC Initialization ------------------------------------------------------

const isProduction = process.env.NODE_ENV === "production";

const t = initTRPC.context<typeof createMemoryTRPCContext>().create({
  transformer: superjson,
  errorFormatter: ({ shape, error }) => {
    const shouldSanitize =
      isProduction && error.code === "INTERNAL_SERVER_ERROR";

    return {
      ...shape,
      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
      data: {
        ...shape.data,
        zodError:
          error.cause instanceof ZodError ? error.cause.flatten() : null,
      },
    };
  },
});

// -- Middleware ----------------------------------------------------------------

const sentryMiddleware = t.middleware(
  trpcMiddleware({
    attachRpcInput: true,
  }),
);

const sentrifiedProcedure = t.procedure.use(sentryMiddleware);

const observabilityMiddleware = t.middleware(
  async ({ next, path, ctx, type }) => {
    if (t._config.isDev) {
      const waitMs = Math.floor(Math.random() * 400) + 100;
      await new Promise((resolve) => setTimeout(resolve, waitMs));
    }

    const { result, journal, durationMs } = await withRequestContext(
      {
        requestId: nanoid(),
        ...(ctx.auth.type === "service" && { caller: ctx.auth.caller }),
      },
      () => next(),
    );

    const meta = {
      path,
      type,
      durationMs,
      ok: result.ok,
